LAYER
  NAME "tendencia_temperatura_maxima_marzo_abril_mayo"
  GROUP "Caracterización Climática"
  STATUS off
  MAXSCALE -1.0
  MINSCALE -1.0
  TYPE point
  TOLERANCE 2
  TOLERANCEUNITS kilometers
  PROCESSING 'LABEL_NO_CLIP=1'
  LABELITEM "nombre"
  LABELMAXSCALEDENOM 800000
  LABELMAXSCALE 800000
  TRANSPARENCY 100
  DUMP true
  HEADER   "plantillas/inicio.html"
  TEMPLATE "plantillas/raster.html"
  FOOTER   "plantillas/fin.html"  
  DATA "the_geom from (select gid, nombre, the_geom from geo.tendencia) as siar using unique gid using srid=32718"
  INCLUDE "configuracion/postgresql_siarcusco.map"
  PROJECTION
	"init=epsg:32718"
  END
  METADATA
	"wms_encoding" "LATIN1"
	"layer_encoding" "LATIN1"
	"wms_group_title" "Caracterización Climática"
	"queryable" "true"
	"wms_metadataurl_type" "TC211"
	"wms_title" "Tendencia temperatura máxima mar,abr,may"
	"wms_abstract" "Tendencia temperatura máxima marzo, abril, mayo - Copyright © Servicio Nacional de Meteorología e Hidrología - SENAMHI, fecha: Junio 2010 :: http://www.senamhi.gob.pe, elaborado para el Programa de Adaptación al Cambio Climático  - PACC Perú 2013 :: http://www.paccperu.org.pe"
	"wms_dataurl_href" "../descargar/tendencia_temperatura_maxima_marzo_abril_mayo.jpg" 
	"autor" "© SENAMHI (Junio 2010) - PACC Perú"
	"wms_extent" "610926.128700 8287114.035600 1004676.654900 8759707.070600"    
	"wms_srs" "EPSG:32718"
	"wms_include_items" "all"
	"wms_exclude_items" "gid"
  END
  CLASS  
	NAME "Sin significancia estadística"
	EXPRESSION ("[nombre]" eq "0")
	COLOR -1 -1 -1
	OUTLINECOLOR -1 -1 -1
  END
  CLASS #1
	NAME "0.035 - 0.07"
	EXPRESSION ("[nombre]" eq "CURAHUASI" OR "[nombre]" eq "SICUANI")
	STYLE		
        SYMBOL "triangulo_vacio"
		COLOR 255 0 0
        SIZE 25
    END
	LABEL
		TYPE TRUETYPE
		FONT "Verdana"
		SIZE 8
		MINSIZE 8
		MAXSIZE 8
		POSITION ur
		OFFSET 0 0 
		BUFFER 0
		MINFEATURESIZE -1
		COLOR 255 255 255
		OUTLINECOLOR 128 128 128
		SHADOWSIZE 0.5 0.5
		ANTIALIAS true
		FORCE true
	END	
  END
